const Observable = require('./src/observable');

class TestObserver {
  constructor() {
    this.events = [];
  }
  update(event) {
    this.events.push(event);
  }
}

const observable = new Observable();
const observer = new TestObserver();

const unsubscribe = observable.subscribe(observer);

console.log('After subscribe:');
console.log('Observer in array:', observable.observers.includes(observer));
console.log('Observer has observable ref:', observer.observable === observable);

unsubscribe();

console.log('\nAfter unsubscribe:');
console.log('Observer in array:', observable.observers.includes(observer));
console.log('Observer still has observable ref:', observer.observable === observable);
console.log('Circular reference persists!');
